// Quantum Entanglement
// Adapted from GenerativeArtGallery / artwork13

let qPairs = [];
let qPrevN = 0;

function qMake(n) {
  let pairs = [];
  for (let i = 0; i < n; i++) {
    let ph = Math.random() * Math.PI * 2;
    pairs.push([
      { x: 60 + Math.random() * 280, y: 60 + Math.random() * 280,
        vx: (Math.random() - 0.5) * 1.5, vy: (Math.random() - 0.5) * 1.5,
        sp: ph, hist: [] },
      { x: 60 + Math.random() * 280, y: 60 + Math.random() * 280,
        vx: (Math.random() - 0.5) * 1.5, vy: (Math.random() - 0.5) * 1.5,
        sp: ph + Math.PI, hist: [] }
    ]);
  }
  return pairs;
}

p.setup = function() {
  p.createCanvas(400, 400);
  p.colorMode(p.HSB, 360, 100, 100, 100);
  p.frameRate(30);
  qPairs = qMake(6);
};

p.draw = function() {
  let pairStr  = p.getSynthVar('pair_count') || 'medium';
  let spinStr  = p.getSynthVar('spin_speed') || 'medium';
  let rangeStr = p.getSynthVar('entangle_range') || 'medium';
  let colorStr = p.getSynthVar('color_mode') || 'complementary';
  let trailStr = p.getSynthVar('trail_length') || 'medium';

  let n       = pairStr === 'few' ? 3 : pairStr === 'medium' ? 6 : 10;
  let spd     = spinStr === 'slow' ? 0.012 : spinStr === 'medium' ? 0.03 : 0.07;
  let dist    = rangeStr === 'close' ? 160 : rangeStr === 'medium' ? 270 : 380;
  let maxHist = trailStr === 'short' ? 18 : trailStr === 'medium' ? 45 : 90;

  if (n !== qPrevN) { qPairs = qMake(n); qPrevN = n; }

  p.background(0, 0, 4, 15);

  qPairs.forEach(function(pair, pi) {
    let h1 = colorStr === 'spectrum' ? (pi / qPairs.length) * 360 :
             colorStr === 'cool' ? 180 + pi * 22 :
             colorStr === 'warm' ? pi * 18 :
             (pi / qPairs.length) * 360;
    let h2 = (h1 + 180) % 360;

    pair[0].sp += spd;
    pair[1].sp = pair[0].sp + Math.PI;

    pair.forEach(function(pt, idx) {
      let partner = pair[1 - idx];
      let dx = partner.x - pt.x, dy = partner.y - pt.y;
      let d = Math.sqrt(dx * dx + dy * dy);
      if (d > dist) { pt.vx += dx / d * 0.09; pt.vy += dy / d * 0.09; }
      if (pt.x < 15) pt.vx += 0.3;
      if (pt.x > 385) pt.vx -= 0.3;
      if (pt.y < 15) pt.vy += 0.3;
      if (pt.y > 385) pt.vy -= 0.3;
      pt.vx *= 0.97; pt.vy *= 0.97;
      pt.x += pt.vx; pt.y += pt.vy;

      pt.hist.push({ x: pt.x, y: pt.y });
      if (pt.hist.length > maxHist) pt.hist.shift();

      let hue = idx === 0 ? h1 : h2;

      for (let k = 1; k < pt.hist.length; k++) {
        let alpha = p.map(k, 0, pt.hist.length, 4, 65);
        p.stroke(hue, 75, 88, alpha);
        p.strokeWeight(1.5);
        p.line(pt.hist[k-1].x, pt.hist[k-1].y, pt.hist[k].x, pt.hist[k].y);
      }

      let ring = 8 + 4 * Math.sin(pt.sp);
      p.noFill();
      p.stroke(hue, 55, 78, 50);
      p.strokeWeight(1);
      p.ellipse(pt.x, pt.y, ring * 2, ring * 2);
      p.noStroke();
      p.fill(hue, 80, 96, 95);
      p.ellipse(pt.x, pt.y, 6, 6);
    });

    // Dashed entanglement link (manual)
    p.stroke(h1, 30, 65, 18);
    p.strokeWeight(0.8);
    let steps = 14;
    for (let k = 0; k < steps; k++) {
      if (k % 2 === 0) {
        let t1 = k / steps, t2 = (k + 0.5) / steps;
        p.line(
          pair[0].x + (pair[1].x - pair[0].x) * t1,
          pair[0].y + (pair[1].y - pair[0].y) * t1,
          pair[0].x + (pair[1].x - pair[0].x) * t2,
          pair[0].y + (pair[1].y - pair[0].y) * t2
        );
      }
    }

    // Interference dot at midpoint
    let mx = (pair[0].x + pair[1].x) / 2;
    let my = (pair[0].y + pair[1].y) / 2;
    let ia = Math.abs(Math.sin(pair[0].sp * 2)) * 45;
    p.noStroke();
    p.fill(h1, 45, 92, ia);
    p.ellipse(mx, my, 14, 14);
  });
};
